INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('narration_activesi_gap_returns_last_sentence', 'Review-site player jumps to the LAST sentence of the state during every inter-sentence gap — a fragment of a DIFFERENT statement is spoken + captioned at each boundary, then snaps back', 'MAJOR', 'peter_parker:renderer_primitives', 'In the build_review_site.ts inline player, activeSiAt(t) maps the clock to the active sentence by scanning each sentence window [start,end). Between sentences computeTimeline() inserts a GAP_MS=280ms breathing gap, during which t matches NO window, so the loop fell through to "return timeline[timeline.length-1].si" — the LAST sentence of the state. The reveal loop (LOOP_MS=90ms) sampled that gap ~3 times per boundary, so applyReveal() repainted the caption AND playCurrent()/speakCurrent() spoke the FINAL sentence for ~280ms, then snapped back when the next window opened. On 3+ sentence states the first gap leapt straight to the last line. This is player-wide (every review-site concept), caught by the founder on parallel_currents_force.', 'In a clock→sentence mapper with inter-sentence gaps, NEVER fall through to the last index. During a gap (or past the end) HOLD the most-recently-STARTED sentence (track held = the last si whose start <= t). A breathing gap must keep the just-finished sentence on screen/in-ear, not jump anywhere.', 'manual', 'On a state with 3+ sentences, watch the boundary between sentence 1 and 2: the caption must hold sentence 1 through the ~280ms gap (never flash the final sentence) and audio must not blurt a different line. Repeat muted to confirm the visual alone is smooth.', 'FIXED', ARRAY['parallel_currents_force'], ARRAY['src/scripts/build_review_site.ts'], 'session_2026-06-27_narration_smoothness', 'incident'),
('narration_cancel_speak_race_browser_tts', 'Review-site narration used browser speechSynthesis with cancel()+speak() at every boundary — a flaky Chrome combo that clips the new utterance / replays the tail of the cancelled one (stutter on top of the wrong-statement jump)', 'MODERATE', 'peter_parker:renderer_primitives', 'The review-site player narrated via window.speechSynthesis (browser Web Speech), and speakCurrent() called speechSynthesis.cancel() immediately followed by speak() on every sentence change. cancel()-then-speak() is a well-known flaky path in Chrome: the new utterance can be dropped, clipped at the start, or the cancelled utterance''s tail can briefly continue. It also made narration non-deterministic (depended on the device''s installed voices) and could not be multilingual.', 'Do NOT drive verified narration through browser speechSynthesis. Use PRE-GENERATED stored audio clips (Sarvam) played via a SINGLE reused <audio> element, always stopAudio() (pause + rewind) before setting src + play() so overlap is structurally impossible. Clock-driven sequencing (Rule 26) stays the source of truth; audio is a passenger. This also unlocks EN/HI/TE narration (Rule 13).', 'manual', 'Narration plays identically every run with no clip/stutter at sentence boundaries; the emitted player contains no window.speechSynthesis / SpeechSynthesisUtterance; switching language and scrubbing across a gap never produces overlapping audio.', 'FIXED', ARRAY['parallel_currents_force'], ARRAY['src/scripts/build_review_site.ts'], 'session_2026-06-27_narration_smoothness', 'incident')
ON CONFLICT (bug_class) DO NOTHING;
